<?php
namespace App\Console\Commands;
use App\Domain\Repayments\Actions\ApplyLatePenalties;use App\Domain\Repayments\Actions\RefreshLoanArrears;use App\Models\Cooperative;use App\Support\Tenancy\TenantContext;use Illuminate\Console\Command;
class ServiceLoanArrearsCommand extends Command{protected $signature='loans:service-arrears';protected $description='Refresh arrears, apply configured penalties, and open recovery cases';public function handle(RefreshLoanArrears $arrears,ApplyLatePenalties $penalties,TenantContext $tenant):int{$updated=0;$applied=0;$cases=0;Cooperative::query()->each(function($cooperative)use($tenant,$arrears,$penalties,&$updated,&$applied,&$cases){$tenant->set($cooperative);$result=$arrears->execute();$updated+=$result['installments_updated'];$cases+=$result['recovery_cases_opened'];$applied+=$penalties->execute();$tenant->clear();});$this->info("Updated {$updated} installments, applied {$applied} penalties, opened {$cases} recovery cases.");return self::SUCCESS;}}
